/**
 *
 * @param axisrotated
 * @param stacked
 * @param xscale
 * @param yscale
 * @param yaxiscolumnorder
 * @param d
 * @param type
 * @param zscale
 * @param yrangePos
 * @returns {*}
 */
//getXY.js
import { DataProcessor } from '../data-processor';
import { mathMax } from '../zc-constants';
// import { polarToXY } from '../../polaraxis/polarutils';
import { d3_polygonCentroid } from '../d3-constants';
import { getSizeFromPoint } from './size/size-from-point';
import { Registry } from '../zc-registry';

const TYPE_REGEX = /(\w+)\(?(\w+)?\)?/;

/**
 * 
 * @param {*} axisrotated 
 * @param {*} stacked 
 * @param {*} xscale 
 * @param {*} yscale 
 * @param {*} yaxiscolumnorder 
 * @param {*} d 
 * @param {'x' | 'y' | 'xy' | 'r' | 'a' | 'ra' | 'r(min)'} type
 * @param {*} zscale 
 * @param {*} yrangePos 
 * @returns 
 */
DataProcessor.prototype.getXYvalue = function(axisrotated, stacked, xscale, yscale, yaxiscolumnorder, d, type, zscale, yrangePos) {
    var model = this,
        yaxesData = this.yaxesData,
        dataset = this.dataset,
        chartObj = this.chartObj;

    const matches = TYPE_REGEX.exec(type),
        is_min = matches[2] === 'min';
    type = matches[1];

    if (model.isPolarAxisCategory) {
        var baseIdx = yaxesData[yaxiscolumnorder].reversed && !stacked ? yscale.domain().length - 1 : 0;
        var a = xscale(dataset.getX(d)),
            r = stacked ? is_min ? yscale(d.y0) : yscale(d.y + d.y0)
                : yscale(dataset.getY(d, yaxiscolumnorder)) + (yscale.bandwidth != null ? yscale.bandwidth() / 2 : 0);
        r = mathMax(r, yscale.range()[baseIdx]);
        if (/^[ra]$/.test(type)) {
            return type == 'r' ? r : type == 'a' ? a : [r, a]
        }

        var xy = Registry.getComponent('geometryUtils.polarToCartesian')(r, a);
        return type == 'xy' ? xy : type === 'x' ? xy[0] : xy[1];
    } else if (model.isFlowChartCategory) {
        let centroid = d._centroid;
        if (!d._centroid || chartObj.phase === 'legendFilter') {
            let polygon = this.chartObj.renderer[0].highlighter.getPolygon(d);
            centroid = polygon.length > 1 ? (d._centroid = d3_polygonCentroid(polygon)) : polygon[0];
        }
        return type === 'x' ? centroid[0] : centroid[1];
    }
    switch (type) {
        case 'x':
            if (axisrotated) {
                return stacked
                    ? yscale(d.y + d.y0)
                    : yscale(dataset.getY(d, yaxiscolumnorder, yrangePos)) + (yscale.bandwidth != null ? yscale.bandwidth() / 2 : 0);
            }
            let xval = dataset.getX(d);
            return xscale(xval) + (xscale.bandwidth != null ? xscale.bandwidth(xval) / 2 : 0);
        case 'y':
            if (axisrotated) {
                let xval = dataset.getX(d);
                return xscale(xval) + (xscale.bandwidth != null ? xscale.bandwidth(xval) / 2 : 0);
            }
            return stacked
                ? yscale(d.y + d.y0)
                : yscale(dataset.getY(d, yaxiscolumnorder, yrangePos)) + (yscale.bandwidth != null ? yscale.bandwidth() / 2 : 0);
        case 'z': {
            return getSizeFromPoint(d, dataset, chartObj);
        }
    }
};
